from flask import Flask, request
from prometheus_client import start_http_server, Collector, GaugeMetricFamily
from prometheus_flask_exporter import PrometheusMetrics

app = Flask(__name__)
PrometheusMetrics(app)

requests_total = Collector(
    'request_total', 'Total number of requests', ['method', 'url']
)
requests_latency = Collector(
    'request_latency_seconds', 'Latency of requests in seconds', ['method', 'url']
)

@app.route('/<path:path>')
def handle_request(path):
    start_time = time.time()
    method = request.method
    url = request.url

    requests_total.labels(method, url).inc()

    response = app.response_class(
        headers={"Content-Type": "text/plain"},
        direct_passthrough=True
    )

    def latency():
        end_time = time.time()
        requests_latency.labels(method, url).observe(end_time - start_time)
        return response

    if path == '/metrics':
        return requests_total.collect()
    else:
        return latency()()

